class _LockstepReceiveStream(ReceiveStream):
    def __init__(self, lbq: _LockstepByteQueue) -> None:
        self._lbq = lbq

    def close(self) -> None:
        self._lbq.close_receiver()

    async def aclose(self) -> None:
        self.close()
        await _core.checkpoint()

    async def receive_some(self, max_bytes: int | None = None) -> bytes | bytearray:
        return await self._lbq.receive_some(max_bytes)

class _LockstepReceiveStream(ReceiveStream) {
  __init__(lbq:_LockstepByteQueue) = self._lbq = lbq
  close() = _lbq.close_receiver()
  aclose() = close() |> await _core.checkpoint()
  receive_some(max_bytes=None)->bytes|bytearray = _lbq.receive_some(max_bytes)
}
